   466	CompoundStmt*
   467	Json2Asg::compound_stmt(const llvm::json::Object& jobj)
   468	{
   469	  auto compoundStmt = make<CompoundStmt>();
   470	
   471	  auto inner = jobj.getArray("inner");
   472	  if (!inner)
   473	    return compoundStmt;
   474	
   475	  for (auto& value : *inner) {
   476	    auto object = value.getAsObject();
   477	    ASSERT(object);
   478	
   479	    compoundStmt->subs.push_back(stmt(*object));
   480	  }
   481	  return compoundStmt;
   482	}
