   484	DeclStmt*
   485	Json2Asg::decl_stmt(const llvm::json::Object& jobj)
   486	{
   487	  auto declStmt = make<DeclStmt>();
   488	  auto inner = jobj.getArray("inner");
   489	  ASSERT(inner);
   490	
   491	  for (auto& value : *inner) {
   492	    auto object = value.getAsObject();
   493	    ASSERT(object);
   494	    if (auto pDecl = decl(*object))
   495	      declStmt->decls.push_back(pDecl);
   496	  }
   497	
   498	  return declStmt;
