   520	  auto inner = jobj.getArray("inner");
   521	  ASSERT(inner);
   522	
   523	  ifStmt->cond = expr(*(inner->front().getAsObject()));
   524	  ifStmt->then = stmt(*((*inner)[1].getAsObject()));
